import{_ as o,o as t,c as e,a3 as i}from"./chunks/framework.BTFg6ESq.js";const h=JSON.parse('{"title":"工具调用 (Tool Calling) 概览","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/tool-calling/index.md","filePath":"user-guide/tools/llm-chat/tool-calling/index.md","lastUpdated":1778244893000}'),a={name:"user-guide/tools/llm-chat/tool-calling/index.md"};function r(n,l,s,g,c,d){return t(),e("div",null,[...l[0]||(l[0]=[i('<h1 id="工具调用-tool-calling-概览" tabindex="-1">工具调用 (Tool Calling) 概览 <a class="header-anchor" href="#工具调用-tool-calling-概览" aria-label="Permalink to &quot;工具调用 (Tool Calling) 概览&quot;">​</a></h1><p>工具调用系统允许智能体（Agent）在对话过程中主动调用 AIO 内部的功能模块（如文件操作、系统指令、API 测试等），从而突破纯文本生成的限制，实现“言行合一”的交互体验。</p><div><h2 id="核心流程" tabindex="-1">核心流程 <a class="header-anchor" href="#核心流程" aria-label="Permalink to &quot;核心流程&quot;">​</a></h2><p>工具调用的完整生命周期如下：</p><ol><li><strong>定义注入</strong>：系统通过 <code>{{tools}}</code> 宏将当前智能体启用的工具定义（名称、描述、参数 Schema）注入到 LLM 的提示词中。</li><li><strong>模型决策</strong>：LLM 根据用户需求，决定是否需要调用工具。如果需要，它会输出符合协议格式的调用请求。</li><li><strong>解析与审批</strong>： <ul><li>系统解析模型输出，识别出工具名称和参数。</li><li>根据<strong>审批策略</strong>（自动或手动），决定是否立即执行。</li></ul></li><li><strong>执行与反馈</strong>： <ul><li>系统在本地执行对应的工具方法。</li><li>执行结果（成功数据或错误信息）被包装为“工具角色”消息，反馈给 LLM。</li></ul></li><li><strong>最终生成</strong>：LLM 根据工具返回的结果，生成最终回复给用户。</li></ol></div><h2 id="协议支持" tabindex="-1">协议支持 <a class="header-anchor" href="#协议支持" aria-label="Permalink to &quot;协议支持&quot;">​</a></h2><p>系统支持多种工具调用协议，以适配不同能力等级的模型：</p><ul><li><strong>VCP (Versatile Chat Protocol)</strong>： <ul><li><strong>特点</strong>：纯文本结构协议，不依赖模型厂商的原生 Tool Calling API。</li><li><strong>优势</strong>：兼容性极强，适用于所有能输出文本的模型（如 DeepSeek、本地 Llama 等）。</li><li><strong>格式</strong>：通常采用 XML 或特定的 Markdown 标记包裹。</li></ul></li><li><strong>厂商原生协议</strong>： <ul><li>支持 OpenAI、Anthropic、Google Gemini 等厂商的标准工具调用接口。</li><li>系统会自动将内部工具定义转换为对应厂商的 JSON Schema。</li></ul></li></ul><h2 id="角色兼容性-converttoolroletouser" tabindex="-1">角色兼容性 (convertToolRoleToUser) <a class="header-anchor" href="#角色兼容性-converttoolroletouser" aria-label="Permalink to &quot;角色兼容性 (convertToolRoleToUser)&quot;">​</a></h2><p>由于部分模型或 API 代理不支持原生的 <code>tool</code> 角色消息，系统提供了“角色转换”功能：</p><ul><li><strong>开启后</strong>：工具的执行结果将伪装成 <code>user</code> 角色的消息发送给模型。</li><li><strong>适用场景</strong>：使用不支持工具角色的纯文本协议（如 VCP）或某些限制严格的 API 渠道时。</li></ul><h2 id="性能与安全控制" tabindex="-1">性能与安全控制 <a class="header-anchor" href="#性能与安全控制" aria-label="Permalink to &quot;性能与安全控制&quot;">​</a></h2><ul><li><strong>并行执行</strong>：支持同时发起多个不相关的工具调用，提升效率。</li><li><strong>最大迭代次数</strong>：限制模型在单次对话中连续调用工具的次数（默认为 20 次），防止因逻辑死循环导致的 Token 浪费。</li><li><strong>超时控制</strong>：为每个工具调用设置硬性超时时间（默认 30s），确保界面响应不会因后台任务卡死。</li></ul><hr><p><strong>相关阅读</strong>：</p><ul><li><a href="./approval-strategy">审批策略与交互</a></li><li><a href="./tool-definition">工具定义与宏注入</a></li><li><a href="./execution-debug">执行监控与异步任务</a></li></ul>',14)])])}const p=o(a,[["render",r]]);export{h as __pageData,p as default};
